func (this *HyperliquidCore) ParseOrder(order any, optionalArgs ...any) any {
	//
	// createOrdersWs error
	//
	//  {error: 'Insufficient margin to place order. asset=159'}
	//
	//  fetchOpenOrders
	//
	//     {
	//         "coin": "ETH",
	//         "limitPx": "2000.0",
	//         "oid": 3991946565,
	//         "origSz": "0.1",
	//         "side": "B",
	//         "sz": "0.1",
	//         "timestamp": 1704346468838
	//     }
	// fetchClosedorders
	//    {
	//        "cloid": null,
	//        "closedPnl": "0.0",
	//        "coin": "SOL",
	//        "crossed": true,
	//        "dir": "Open Long",
	//        "fee": "0.003879",
	//        "hash": "0x4a2647998682b7f07bc5040ab531e1011400f9a51bfa0346a0b41ebe510e8875",
	//        "liquidationMarkPx": null,
	//        "oid": "6463280784",
	//        "px": "110.83",
	//        "side": "B",
	//        "startPosition": "1.64",
	//        "sz": "0.1",
	//        "tid": "232174667018988",
	//        "time": "1709142268394"
	//    }
	//
	//  fetchOrder
	//
	//     {
	//         "order": {
	//             "children": [],
	//             "cloid": null,
	//             "coin": "ETH",
	//             "isPositionTpsl": false,
	//             "isTrigger": false,
	//             "limitPx": "2000.0",
	//             "oid": "3991946565",
	//             "orderType": "Limit",
	//             "origSz": "0.1",
	//             "reduceOnly": false,
	//             "side": "B",
	//             "sz": "0.1",
	//             "tif": "Gtc",
	//             "timestamp": "1704346468838",
	//             "triggerCondition": "N/A",
	//             "triggerPx": "0.0"
	//         },
	//         "status": "open",
	//         "statusTimestamp": "1704346468838"
	//     }
	//
	// createOrder
	//
	//     {
	//         "resting": {
	//             "oid": 5063830287
	//         }
	//     }
	//
	//     {
	//        "filled":{
	//           "totalSz":"0.1",
	//           "avgPx":"100.84",
	//           "oid":6195281425
	//        }
	//     }
	// frontendOrder
	// {
	//     "children": [],
	//     "cloid": null,
	//     "coin": "BLUR",
	//     "isPositionTpsl": false,
	//     "isTrigger": true,
	//     "limitPx": "0.5",
	//     "oid": 8670487141,
	//     "orderType": "Stop Limit",
	//     "origSz": "20.0",
	//     "reduceOnly": false,
	//     "side": "B",
	//     "sz": "20.0",
	//     "tif": null,
	//     "timestamp": 1715523663687,
	//     "triggerCondition": "Price above 0.6",
	//     "triggerPx": "0.6"
	// }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var error any = this.SafeString(order, "error")
	if IsTrue(!IsEqual(error, nil)) {
		return this.SafeOrder(map[string]any{
			"info":   order,
			"status": "rejected",
		})
	}
	var entry any = this.SafeDictN(order, []any{"order", "resting", "filled"})
	if IsTrue(IsEqual(entry, nil)) {
		entry = order
	}
	var filled any = this.SafeDict(order, "filled", map[string]any{})
	var coin any = this.SafeString(entry, "coin")
	var marketId any = nil
	if IsTrue(!IsEqual(coin, nil)) {
		marketId = this.CoinToMarketId(coin)
	}
	if IsTrue(IsEqual(this.SafeString(entry, "id"), nil)) {
		market = this.SafeMarket(marketId, nil)
	} else {
		market = this.SafeMarket(marketId, market)
	}
	var symbol any = GetValue(market, "symbol")
	var timestamp any = this.SafeInteger(entry, "timestamp")
	var status any = this.SafeString2(order, "status", "ccxtStatus")
	order = this.Omit(order, []any{"ccxtStatus"})
	var side any = this.SafeString(entry, "side")
	if IsTrue(!IsEqual(side, nil)) {
		side = Ternary(IsTrue((IsEqual(side, "A"))), "sell", "buy")
	}
	var totalAmount any = this.SafeString2(entry, "origSz", "totalSz")
	var remaining any = this.SafeString(entry, "sz")
	var tif any = this.SafeStringUpper(entry, "tif")
	var postOnly any = nil
	if IsTrue(!IsEqual(tif, nil)) {
		postOnly = (IsEqual(tif, "ALO"))
	}
	return this.SafeOrder(map[string]any{
		"info":                order,
		"id":                  this.SafeString(entry, "oid"),
		"clientOrderId":       this.SafeString(entry, "cloid"),
		"timestamp":           timestamp,
		"datetime":            this.Iso8601(timestamp),
		"lastTradeTimestamp":  nil,
		"lastUpdateTimestamp": this.SafeInteger(order, "statusTimestamp"),
		"symbol":              symbol,
		"type":                this.ParseOrderType(this.SafeStringLower(entry, "orderType")),
		"timeInForce":         tif,
		"postOnly":            postOnly,
		"reduceOnly":          this.SafeBool(entry, "reduceOnly"),
		"side":                side,
		"price":               this.SafeString(entry, "limitPx"),
		"triggerPrice":        Ternary(IsTrue(this.SafeBool(entry, "isTrigger")), this.SafeNumber(entry, "triggerPx"), nil),
		"amount":              totalAmount,
		"cost":                nil,
		"average":             this.SafeString(entry, "avgPx"),
		"filled":              this.SafeString(filled, "totalSz", Precise.StringSub(totalAmount, remaining)),
		"remaining":           remaining,
		"status":              this.ParseOrderStatus(status),
		"fee":                 nil,
		"trades":              nil,
	}, market)
}
func (this *HyperliquidCore) ParseOrderStatus(status any) any {
	if IsTrue(IsEqual(status, nil)) {
		return nil
	}
	var statuses any = map[string]any{
		"triggered":      "open",
		"filled":         "closed",
		"open":           "open",
		"canceled":       "canceled",
		"rejected":       "rejected",
		"marginCanceled": "canceled",
	}
	if IsTrue(EndsWith(status, "Rejected")) {
		return "rejected"
	}
	if IsTrue(EndsWith(status, "Canceled")) {
		return "canceled"
	}
	return this.SafeString(statuses, status, status)
}
func (this *HyperliquidCore) ParseOrderType(status any) any {
	var statuses any = map[string]any{
		"stop limit":  "limit",
		"stop market": "market",
	}
	return this.SafeString(statuses, status, status)
}

